"""
mkt-original Layer — Exodus chapters 22–24
Run: python3 scripts/zc-original-exodus-22-24-fill.py

Key philological decisions:
- Ch 22: shalom (restitution); kashaph (sorcery); ger/yatom/almanah triad (protected classes);
  neshek (interest = bite); salmah (cloak-as-pledge) — if taken, must return by nightfall;
  treifah (torn by predator — first kashrut term outside dietary laws).
- Ch 23: achar rabim (following the crowd — anti-mob-justice law); enemy-love laws (vv.4-5);
  lo tevashel gedi b'chalav imo (kid in mother's milk — foundational kashrut prohibition);
  mal'ach (angel) with YHWH's name in him; tzirah (hornet/panic — divine terror weapon).
- Ch 24: na'aseh v'nishma (we will do and we will hear — Sinai's double assent);
  dam ha-brit (blood of the covenant — Jesus cites at Last Supper, Matt 26:28);
  sefer ha-brit (book of the covenant — first Torah writing);
  kavod YHWH shakan (glory of YHWH dwelt/tabernacled — root of later tabernacle name);
  arba'im yom v'lailah (forty days — the inaugural 40-day period on Sinai).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS_ORIGINAL = {
  "22": {
    "1": "<p><b>If a man steals (ganov yignov) an ox (shor) or a sheep (seh):</b> The doubled infinitive absolute ganov yignov (steal he steals) emphasizes the definite act. The asymmetric restitution — five oxen for one stolen ox, four sheep for one stolen sheep — reflects their relative economic value in ancient Israel: an ox was a working animal critical for plowing and food production; a sheep was smaller capital. The fivefold restitution for ox is the highest in the Code; theft of an ox effectively deprives a family of its livelihood.</p>",
    "2": "<p><b>If a thief is found breaking in (bamachtereth) and is struck and dies:</b> Machtereth = the act of tunneling through a wall (from chatar, to dig/burrow); breaking into a house at night through the wall rather than the door. The law permits lethal self-defense at night — the darkness makes the intruder's intent uncertain. <b>There shall be no blood guilt (ein lo damim):</b> Damim (bloods, plural) = blood guilt/liability; the homeowner is not guilty of murder because he acted in self-defense under conditions of uncertainty.</p>",
    "3": "<p><b>But if the sun has risen on him (im zarach hashemesh alav), there shall be blood guilt:</b> Daylight changes the moral calculus — in the daytime the homeowner can see the intruder and assess the threat; lethal force is not presumptively necessary. The distinction is one of the oldest graduated lethality-in-self-defense principles in legal history. <b>The thief shall make restitution (shalleim y'shalleim):</b> Shalom = peace/wholeness; shilleim = to make whole/restore; the doubled form is the standard legal intensifier for binding obligation.</p>",
    "4": "<p><b>If the stolen animal is found alive in his possession:</b> The living animal in hand is evidence; restitution is twofold (double, not fivefold) because the animal has not been slaughtered or sold — the theft was caught before its consequences were fully enacted. The principle: restitution scales with the harm actually done, not just the crime attempted.</p>",
    "5": "<p><b>If a man causes a field or vineyard to be grazed over (ba'er) by letting his livestock loose:</b> Ba'ar = to consume by grazing or burning; the root covers both animals browsing and fire consuming. The principle of negligent damage: the owner is responsible for what his livestock does on others' land. <b>He shall make restitution from the best of his own field:</b> The quality standard — meitav (the best/finest) — ensures the offended party receives above-replacement value, incentivizing careful livestock management.</p>",
    "6": "<p><b>If fire breaks out and catches in thorns (qotzim):</b> Qotzim = thorns/briers; the dry thorns of the Palestinian summer are classic fire fuel. The law addresses negligent fire spread — someone burning a field who allows the fire to escape into a neighbor's grain or standing crops. Responsibility follows the ignition source, regardless of wind direction.</p>",
    "7": "<p><b>If a man gives his neighbor money or goods to keep (lishmor):</b> Shamar = to guard/keep watch; the safekeeping/bailment relationship (mishmeret = guardianship). The stolen goods from a trusted keeper entail a different liability than open theft; the keeper must prove innocence before elohim (the judges or the divine tribunal).</p>",
    "8": "<p><b>If the thief is not found, the owner of the house shall come near to God (ha-Elohim):</b> Ha-Elohim in the judicial sense = divine tribunal or judges acting as divine representatives. The repeated el ha-Elohim in this section (vv.8,9) may refer to a formal oath-taking before God or before human judges who represent divine authority. Disputed property cases go to the divine tribunal — human courts operate under divine oversight.</p>",
    "9": "<p><b>For every breach of trust (kol-davar pesha') — for ox, donkey, sheep, garment, or any lost thing:</b> Pesha' = transgression/rebellion (the strongest Hebrew word for sin — deliberate violation of relationship); here used for breach of trust/fiduciary duty. Both parties bring their case before ha-Elohim; the guilty party pays double. The doubling principle (mishneh) is the base penalty in disputed cases.</p>",
    "10": "<p><b>If a man gives his neighbor a donkey or ox or sheep or any beast to keep:</b> The bailment law continues; the keeper who watches an animal that dies or is injured without witnesses (ein re'eh) swears an oath (shevuat YHWH) that he did not lay his hand on it — the oath transfers the case from human to divine adjudication.</p>",
    "11": "<p><b>An oath by YHWH shall be between them both:</b> Shevuat YHWH = YHWH's oath/oath-by-YHWH; the divine name functions as the ultimate guarantor of truthfulness. The owner accepts the oath and the keeper is absolved — no restitution. If the animal is stolen (after the oath), the keeper must make restitution; the oath covered negligence, not theft.</p>",
    "12": "<p><b>If it was stolen from him, he shall make restitution to its owner:</b> The keeper who allows theft bears liability — the obligation of safekeeping includes protecting from theft. But if torn by wild animals (tarof yitaref), the keeper brings the evidence (the torn carcass) and is absolved; he swears he did not eat it (lo yeshalleim).</p>",
    "13": "<p><b>If a wild beast has torn it (tarof yitaref), let him bring it as evidence:</b> The doubled tarof yitaref (torn it was torn) signals the severity and definiteness of the loss. The torn carcass (ha-terefa) is brought as legal evidence of force majeure — the keeper cannot be held liable for acts of predation he could not prevent.</p>",
    "14": "<p><b>If a man borrows (yish'al) anything from his neighbor and it is injured or dies:</b> Sha'al = to ask/borrow/request; the loan relationship (she'elah) creates the strictest liability — the borrower who uses another's animal bears full responsibility if it is harmed while in his use. <b>The owner not being with it, he shall make full restitution:</b> The owner's absence is the key legal fact; if the owner was present (imo, with him), the liability is reduced because the owner participated in the use.</p>",
    "15": "<p><b>If the owner was with it, he shall not make restitution:</b> The owner's presence (imo = with him) during the use means he bears joint risk and has no claim. <b>If it was hired, it came for its hire:</b> The hired animal's risk is priced into the rental fee (sekaro ba ba'avuro = its wage came in its wages) — the renter has already paid for the assumed risk.</p>",
    "16": "<p><b>If a man seduces (yefateh) a virgin who is not betrothed:</b> Pathah = to entice/persuade/seduce (also used of prophetic inspiration gone wrong — Jer 20:7); the consensual seduction of an unbetrothed virgin. The man must pay the mohar (bride price) and marry her — the legal remedy prioritizes the woman's long-term social protection over punitive measures. If her father refuses the marriage, the man still pays the full mohar.</p>",
    "17": "<p><b>If her father utterly refuses to give her to him:</b> The father's veto (refusal to give = me'en yema'en) is legally binding; the daughter cannot be forced to marry her seducer if her father objects. <b>He shall pay money equal to the bride price for virgins (kemoharn'betulot):</b> Mohar = bride price (the payment from groom to bride's family that transferred legal responsibility and provided the bride with economic security); betulot = virgins.</p>",
    "18": "<p><b>You shall not permit a sorceress (m'kashapha) to live:</b> Kashaph = to practice sorcery/witchcraft; the participle form identifies the person by ongoing practice. The feminine form (m'kashapha) is notable — sorcery was predominantly associated with women in ancient Near Eastern contexts. The capital penalty reflects the seriousness of the offense: the sorcerer claims to mediate between the human and divine realms outside YHWH's authorization.</p>",
    "19": "<p><b>Whoever lies with an animal (shochev im behemah) shall be put to death:</b> Shachav = to lie/sleep with (the standard sexual euphemism); behemah = beast/livestock. The death penalty covers both human and animal (Lev 20:15-16). The violation of the created order (Gen 1's separation of species) is the underlying rationale; sexual congress across species categories inverts the creation mandate.</p>",
    "20": "<p><b>Whoever sacrifices (zovach) to any god (la-elohim acherim) other than YHWH alone shall be devoted to destruction (yochoram):</b> Zovach = to slaughter as sacrifice; cherem (related to yochoram) = the devoted ban — complete destruction as YHWH's property, the highest and most irrevocable sanction in Israel's law. Sacrificing to other gods is not merely religious deviance but treason against the suzerain of the covenant.</p>",
    "21": "<p><b>You shall not wrong (toneh) a sojourner (ger):</b> Yanah = to oppress/wrong/maltreat; ger = resident alien/sojourner (from gur, to sojourn/live as a guest). The ger is the vulnerable outsider living within Israelite society without tribal protection. The grounding for the prohibition is covenantal memory: you were gerim in Egypt (ki gerim heyitem b'eretz mitzrayim). Israel's experience of oppression creates the ethical obligation to protect those in the same social position.</p>",
    "22": "<p><b>You shall not afflict (t'anun) any widow (almanah) or fatherless child (yatom):</b> Anah = to afflict/humble/oppress; almanah = widow (a woman without a male protector); yatom = orphan (literally fatherless — without a father's economic protection). The almanah-yatom-ger triad recurs throughout the law codes and prophets as the paradigm of the vulnerable for whom YHWH himself acts as protector. Their mistreatment triggers direct divine response.</p>",
    "23": "<p><b>If you do afflict them and they cry out to me (veitz'aku elai):</b> Za'aq = to cry out in distress (the same verb as 2:23 — the slaves' cry); YHWH responds to the cry of the powerless with wrath (charah appi). The consequence is in kind: their widows and orphaned children (almnoteihem yih'yu almanot, u'vneichem yetomim) mirror the oppressor's victims. The covenant law has a built-in retributive logic: do to others what was done to you in Egypt, and I will do to your families what Egypt did to you.</p>",
    "24": "<p><b>If you lend money (halveh) to any of my people who is poor (aniy):</b> Lavah = to lend/borrow (the borrower is servant to the lender — Prov 22:7 uses the same root). <b>You shall not be like a moneylender (k'nosheh) to him, and you shall not exact interest (neshek):</b> Nosheh = one who drives/exacts; neshek = interest (literally a bite — from nashak, to bite; interest that bites into principal). The anti-usury law is rooted in covenantal solidarity: the poor Israelite is ach (brother), not a business opportunity.</p>",
    "25": "<p><b>If you ever take your neighbor's cloak (salmah) in pledge (chabol tachbelenu):</b> Salmah = garment/cloak (the outer garment that doubled as a blanket); chabol = to take a pledge/hold as security (from chebl = cord/band). The poor man's only covering — his cloak — cannot be permanently retained as collateral. <b>You shall return it to him before the sun goes down:</b> The sunset deadline (ad-ba hashemesh) transforms property law into a humanitarian obligation; the cloak is not merely collateral but the man's bedding.</p>",
    "26": "<p><b>For that is his only covering (ki hi kesuto levadah):</b> Levadah = alone/only; kesut = covering. <b>It is his cloak for his body; in what else shall he sleep?</b> The rhetorical question (b'mah yishkav?) is an appeal to empathy embedded in the law itself. <b>And if he cries to me, I will hear, for I am compassionate (chanun ani):</b> Chanun = gracious/compassionate (one of the divine attributes of Exod 34:6-7); the same word used of YHWH's character at Sinai. The covenant law is not just a social contract but a reflection of the divine character.</p>",
    "27": "<p><b>You shall not revile God (elohim lo teqallel) nor curse a ruler (nasi) of your people:</b> Qalal = to make light, curse, hold in contempt; elohim here may refer to God directly or to judges/rulers as divine representatives (the word is ambiguous in this context; the LXX reads 'gods' = judges). Nasi = leader/prince (literally 'one lifted up' from nasa'). Both the divine order and human governance are protected from the same verb — profaning authority at any level dishonors the structure YHWH has established.</p>",
    "28": "<p><b>You shall not delay to offer from the fullness of your harvest (male'atcha) and from the outflow of your presses (dem'acha):</b> Male'ah = fullness/abundance; dema' = the first pressing/overflow of pressed grapes or oil. <b>The firstborn of your sons you shall give to me:</b> The firstborn son (bechor) dedication principle (cf. 13:2); the male is given to YHWH — later redeemed by the Levites (Num 3) or by the five-shekel redemption price.</p>",
    "29": "<p><b>You shall do the same with your oxen and with your sheep:</b> The parallel between firstborn sons and firstborn animals in vv.28-30 frames the entire created order as YHWH's — humans and animals both subject to the firstborn principle. <b>Seven days it shall be with its mother (shiv'at yamim yihyeh im-imo):</b> The seven-day nursing period before separation echoes the creation week; the animal is given time to bond before being dedicated — a compassionate interval even in the consecration law.</p>",
    "30": "<p><b>On the eighth day (bayom hash'mini) you shall give it to me:</b> The eighth day = the day after the complete week, the day of new beginnings. Circumcision also occurs on the eighth day (Gen 17:12). The pattern of seven-plus-one (fullness + new beginning) structures both animal dedication and human covenant initiation.</p>",
    "31": "<p><b>You shall be consecrated people to me (anshei qodesh tih'yun li):</b> Anshei qodesh = men of holiness/consecrated people; the dietary conclusion of chapter 22 is framed as a holiness identity-statement, not merely a health rule. <b>Therefore you shall not eat any flesh that is torn by beasts in the field (treifah):</b> Treifah (from taraf, to tear/rend) = an animal killed by a predator in the field; this is the first explicit kashrut (dietary law) category outside the Leviticus system. <b>You shall throw it to the dogs (la-kelev tashlichun oto):</b> The torn carcass goes to scavengers — Israel is holy; scavenger food belongs to scavengers.</p>"
  },
  "23": {
    "1": "<p><b>You shall not spread a false report (lo tissa shav):</b> Nasa' = to lift up/carry; shav = emptiness/falsehood/vanity (the same word as the third commandment's 'in vain' — lo tissa et-shem YHWH lashav). To carry a false report is to do with a neighbor's reputation what the commandment forbids doing with YHWH's name. <b>You shall not join hands with a wicked man to be a malicious witness (ed chamas):</b> Ed chamas = witness of violence/injustice; chamas = violence/wrongdoing (the same term for the corruption that preceded the Flood, Gen 6:11). False witness is an act of violence against the innocent.</p>",
    "2": "<p><b>You shall not follow a majority to do evil (lo-tih'yeh acharei rabim l'ra'ot):</b> Acharei rabim = after the many/majority; the law against mob justice — the majority principle applies to voting majorities in court cases but not to mob action. <b>Nor shall you be partial (tit'neh) to a poor man in his lawsuit:</b> Natal = to incline/be partial; even the poor (dal = thin/weak) receive no automatic benefit of judicial partiality. Justice is not a redistribution mechanism but a truth-seeking process.</p>",
    "3": "<p><b>You shall not be partial to a poor man (dal) in his lawsuit:</b> The prohibition of favoritism toward the poor in court — a surprising law that balances the many laws protecting the poor from oppression. Justice is impartial; poverty does not create automatic legal advantage. Cf. Lev 19:15: 'you shall not be partial to the poor or defer to the great.'</p>",
    "4": "<p><b>If you meet your enemy's (oyivcha) ox or his donkey going astray, you shall bring it back to him:</b> Oyev = enemy (personal adversary, not necessarily a foreign enemy). The return of the enemy's stray animal is the first formal enemy-love law in the Hebrew Bible — predating and forming the backdrop to Jesus's 'love your enemies' (Matt 5:44). The law does not require loving feelings but loving actions: the animal must be returned regardless of the relationship.</p>",
    "5": "<p><b>If you see the donkey of one who hates you (son'acha) lying down under its burden:</b> Sone' = one who hates/is hostile to you; the law extends even to the enemy's animal. <b>You shall refrain from leaving him with it; you shall rescue it with him (azov ta'azov imo):</b> The doubled infinitive absolute (azov ta'azov) is emphatic — you shall certainly help. The phrasing 'with him' (imo) implies joint effort; the law creates a situation of forced cooperation between enemies. Working side by side to rescue an animal is itself a social reconciliation mechanism.</p>",
    "6": "<p><b>You shall not pervert the justice (mishpat) due to your poor (evyoncha) in his lawsuit:</b> Evyon = destitute/poor (a stronger term than dal — the utterly impoverished, with no resources); mishpat = justice/judgment/rule. The legal system must serve the poor; its primary test is whether it protects the powerless. The poor man's case (rib = dispute/case/lawsuit) must be heard on its merits.</p>",
    "7": "<p><b>Keep far from a false charge (davar shav):</b> Shav = emptiness/falsehood (same as v.1); <b>Do not kill the innocent (naqi) and righteous (tzaddiq):</b> Naqi = clean/innocent; tzaddiq = righteous/in the right. <b>For I will not acquit the wicked (rasha'):</b> YHWH's own justice is the model and guarantee for the human court; the divine standard backs the human legal order.</p>",
    "8": "<p><b>And you shall take no bribe (shochad):</b> Shachad = a gift/bribe offered to pervert justice; shochad = the bribe. <b>For a bribe blinds the clear-sighted (piqchim) and subverts the cause of those who are in the right (tzaddiqim):</b> Piqeach = one who sees clearly/is sighted (the opposite of blind); the bribe reverses vision — the seeing become blind, the righteous become perverted. The bribery prohibition is the foundational anti-corruption clause of Israelite jurisprudence.</p>",
    "9": "<p><b>You shall not oppress (tilchatz) a sojourner (ger):</b> Lachatz = to press/oppress/squeeze (related to the Egyptian lachatz in 3:9 — the oppression Israel experienced). <b>You know the heart (nefesh) of a sojourner:</b> The use of nefesh (soul/inner life) for 'the experience/feeling of a foreigner' is striking — Israel is commanded to empathize with the ger's inner life because they know it experientially. The ethical command is grounded in experiential memory, not abstract principle.</p>",
    "10": "<p><b>For six years (shesh shanim) you shall sow your land:</b> The sabbath-year (shemittah) law opens with the positive command: six years of full cultivation. The Sabbath principle extends from the week to the year — creation rest is built into the agricultural calendar. Israel's economy must breathe.</p>",
    "11": "<p><b>But in the seventh year (hashevii't) you shall let it rest and lie fallow (tishmetennah u'netashtah):</b> Shamat = to release/remit/let fall; natash = to let loose/abandon. The land gets rest — not merely a human agricultural technique but a theological statement: the land belongs to YHWH and must observe his rest (cf. Lev 25:2-4). <b>That the poor of your people (aniyei ammecha) may eat:</b> The fallow year's produce is freely available to the poor — the land's rest creates a welfare system for those who cannot purchase food. What the land produces without cultivation belongs to all.</p>",
    "12": "<p><b>Six days you shall do your work, but on the seventh day you shall rest (tishbot):</b> Shavat = to cease/rest (the Sabbath verb from shabat); the Sabbath law restated in the social context of the Covenant Code — not just a creation ordinance but a social one. <b>That your ox and your donkey may have rest, and the son of your servant woman and the alien (ger) may be refreshed (yinnafesh):</b> Nafash = to take breath/be refreshed (from nefesh = breath/soul); even animals and resident aliens participate in the Sabbath rest. The Sabbath is the great equalizer: for one day, master and slave, citizen and alien, human and animal all rest together.</p>",
    "13": "<p><b>Pay attention to all that I have said to you, and make no mention of the names of other gods (shem elohim acherim):</b> The law against invoking the names of foreign deities — shem (name) + zakar (to remember/mention). Names were not merely labels but invocations of power; to speak the name of a god was to invite its presence. The prohibition is reinforced: 'let it not be heard on your lips (lo yishama al-picha)' — the absolute exclusion of pagan invocation from Israelite speech.</p>",
    "14": "<p><b>Three times in the year (shalosh regalim) you shall keep a feast to me:</b> Shalosh regalim = three foot-pilgrimages (regel = foot; the festivals were occasions for physical pilgrimage to the central sanctuary). The pilgrim-festival system is the organizing principle of Israel's annual liturgical calendar, integrating agricultural rhythms with redemptive history.</p>",
    "15": "<p><b>You shall keep the Feast of Unleavened Bread (chag hamatzot):</b> The spring festival (month of Abib) commemorates the Exodus; seven days of matzot = the re-enacted experience of the departure. <b>None shall appear before me empty-handed (lo-yeira'u fanai reqam):</b> The Niphal of ra'ah (to be seen before) — pilgrimage to YHWH's presence requires bringing an offering; appearing empty-handed (reqam = empty) is not an option. The offering is the form of the encounter.</p>",
    "16": "<p><b>You shall keep the Feast of Harvest (chag hakatzir), of the firstfruits (bikkurim) of your labor:</b> Katzir = harvest; bikkurim = firstfruits (from bakar, to be first); the late-spring grain festival, later called Shavuot (Weeks) or Pentecost (50 days from Passover). <b>And the Feast of Ingathering (chag ha'asif) at the end of the year:</b> Asif = gathering in; the autumn harvest festival (later called Sukkot = Booths), when all crops are brought in before the rains. The three festivals map the agricultural year (spring planting → early harvest → late harvest) onto redemptive commemoration.</p>",
    "17": "<p><b>Three times in the year all your males shall appear before the Lord YHWH (yira'eh kol-z'kurcha el-p'nei ha'adon YHWH):</b> The triple pilgrimage requirement creates a national rhythm of covenant renewal; every adult male physically presents himself before YHWH's presence three times annually. The use of ha'adon (the Lord/Master) alongside YHWH is rare — the full divine title emphasizes the feudal-suzerain relationship of the Covenant.</p>",
    "18": "<p><b>You shall not offer the blood of my sacrifice with anything leavened (chametz):</b> Sacrificial blood and leavened bread cannot occupy the same space — the unleavened purity of the Passover extends to all blood-sacrifice. <b>The fat (chelev) of my feast shall not remain until morning:</b> Chelev = the richest fat portions dedicated to YHWH; they must be consumed the same night — no overnight storage of the dedicated portions.</p>",
    "19": "<p><b>The best (reshit) of the firstfruits (bikkurei) of your ground you shall bring to the house of YHWH your God:</b> Reshit = beginning/best/firstling; bikkurim = firstfruits; the double emphasis (best + first) maximizes the offering. <b>You shall not boil a young goat in its mother's milk (lo tevashel gedi bachalav imo):</b> The foundational prohibition of kashrut meat/milk separation; it appears three times in the Torah (here, Exod 34:26, Deut 14:21). The exact rationale is debated: Canaanite ritual practice? Compassion for the maternal bond? A symbolic refusal to use the life-giving substance (milk) to destroy life (boiling)? The Talmud extends it to complete separation of meat and dairy.</p>",
    "20": "<p><b>Behold, I send an angel (malach) before you to guard you on the way and to bring you to the place that I have prepared:</b> Malach = messenger/angel (from the root for mission/commission); this is the mal'ach ha-panim (angel of the presence) — the divine emissary who accompanies Israel through the wilderness. <b>Guard you on the way (lishmorcha baderech) and to bring you to the place:</b> The angel serves as both protector and guide, performing the same functions as the pillar of cloud and fire.</p>",
    "21": "<p><b>Pay careful attention to him and obey his voice; do not rebel (al-tammer) against him:</b> Marar = to be bitter/rebellious; the cognate of marah (the bitter waters). <b>For he will not pardon your transgression (lo yissa l'pish'achem):</b> Nasa' = to carry/bear/forgive; the angel will not bear/forgive rebellion because YHWH's name is in him (ki shmi bo = for my name is in him). The angel's authority is derivative — his name is YHWH's name; rebellion against the angel is rebellion against YHWH.</p>",
    "22": "<p><b>But if you carefully obey his voice and do all that I say, then I will be an enemy to your enemies (v'ayavti et-oyavecha) and an adversary to your adversaries (v'tzarti et-tzorecha):</b> The covenant protective formula — YHWH mirrors Israel's conflict relationships. Oyev/tzar (enemy/adversary) are both political and spiritual terms; the protection covers all who oppose Israel's covenant fidelity.</p>",
    "23": "<p><b>When my angel goes before you and brings you to the Amorites and the Hittites and the Perizzites and the Canaanites, the Hivites and the Jebusites, and I blot them out (v'hichadtiv):</b> Six-nation formula (vs. the usual seven or ten — variations signal different sources or rhetorical contexts); hachadah = to cut off/destroy. The extermination of the Canaanite nations is here presented as the direct act of YHWH through his angel — not Israelite military prowess but divine warfare.</p>",
    "24": "<p><b>You shall not bow down to their gods (lo tishtacheveh l'eloheihem) or serve them (lo ta'avdem):</b> Shachah = to prostrate/bow in worship; abad = to serve/work; the two verbs of religious service are prohibited together. <b>You shall utterly overthrow them (ki haros tiharesem) and break their pillars (v'shabeir t'shabeir matzevotam) in pieces:</b> Haras = to tear down; shabar = to break/shatter; matzevah = standing stone/sacred pillar (the Canaanite cultic monuments that YHWH requires destroyed).</p>",
    "25": "<p><b>You shall serve (avadtem) YHWH your God, and he will bless your bread and your water:</b> The exclusive service formula: avad YHWH (to serve/work for YHWH) is the positive counterpart to the prohibition of serving foreign gods. <b>I will take sickness (machalah) away from among you:</b> Machalah = disease/sickness (cf. 15:26 — YHWH the healer); the covenant blessing of health is the positive form of the disease-threat (Deut 28's curse list). Obedience → blessing of provision; disobedience → curse of disease.</p>",
    "26": "<p><b>None shall miscarry (m'shakkelet) or be barren (aqarah) in your land:</b> Shakol = to miscarry/lose young (the verb of Rachel's fear and Jacob's grief — Gen 31:38, 43:14); aqarah = barren (the term for Sarah, Rebekah, Rachel, Hannah — all whose barrenness precedes miraculous birth). The covenant blessing reverses the curse of infertility; covenant fidelity produces abundant offspring. <b>I will fulfill the number of your days (et-mispar yamecha amaleh):</b> Long life as covenant blessing — the years of one's life are in YHWH's hand to complete.</p>",
    "27": "<p><b>I will send my terror (emati) before you:</b> Emah = terror/dread (the same word as the Song of the Sea, 15:16 — 'terror and dread fall upon them'); the divine terror-weapon precedes Israel's advance. <b>I will throw into confusion (hamoti) all the people against whom you shall come:</b> Hamam = to throw into confusion/panic (the same verb as 14:24 — YHWH throwing the Egyptian army into panic); divine warfare tactics: terror sent ahead, confusion at contact.</p>",
    "28": "<p><b>I will send hornets (tzirah) before you:</b> Tzirah = hornet (an actual species, but also possibly a metaphor for terror-inducing panic or a supernatural agent); the word appears only here, Deut 7:20, and Josh 24:12. Whether literal insects or a metaphor for the demoralizing terror that drives nations into flight, the tzirah accomplishes what the human army alone cannot: pre-battlefield psychological collapse. <b>Which shall drive out (v'gershah) the Hivite, the Canaanite, and the Hittite from before you:</b> Garash = to drive out/expel (the verb of expulsion from Eden — Gen 3:24; and of Pharaoh expelling Moses — Exod 10:11).</p>",
    "29": "<p><b>I will not drive them out from before you in one year, lest the land become desolate (shamamah) and the wild beasts (chayat hasadeh) multiply against you:</b> Shamamah = desolation/waste; the theological realism of the conquest — a sudden total expulsion would leave the land uninhabitable. YHWH's timing serves both Israel's security and the land's ecological stability. The text acknowledges the complexity of settling a land that has been cultivated by others: vacated land becomes wild.</p>",
    "30": "<p><b>Little by little (meat meat) I will drive them out from before you, until you have increased and possess the land:</b> Meat meat = a little a little (the repeated diminutive for gradual process); the same principle applies to spiritual formation — YHWH works incrementally, matching the pace to the people's readiness. <b>Until you have increased (parita) and possess the land:</b> Parah = to be fruitful/multiply (the creation blessing verb of Gen 1:28); Israel's growth justifies the expansion of settlement.</p>",
    "31": "<p><b>I will set your border from the Red Sea to the Sea of the Philistines (Yam Pelishtim), and from the wilderness to the Euphrates (Nahar):</b> The maximal promised land dimensions — from Yam Suph (Gulf of Aqaba) to the Mediterranean (Yam Pelishtim), from the Arabian desert to the Euphrates. This is the territorial ideal, partially realized under David and Solomon (1 Kgs 4:21). <b>For I will give the inhabitants of the land into your hand:</b> The divine land-gift is the basis for human military action; the conquest is YHWH's work, not Israel's.</p>",
    "32": "<p><b>You shall make no covenant (lo tichrot lahem brit) with them or with their gods:</b> Karat brit = to cut a covenant (the technical term for covenant-making, from the cutting of the covenant sacrifice — Gen 15:18); the prohibition of covenant-making with Canaanites is comprehensive: no political treaty, no religious accommodation. The exclusive loyalty demanded by the covenant brooks no competing alliance structure.</p>",
    "33": "<p><b>They shall not dwell in your land, lest they make you sin against me (yachatiu otcha li):</b> Chata = to miss the mark/sin; the resident Canaanites would serve as a mokesh (snare/trap — from yaqash, to trap birds) — a mechanism drawing Israel into their religious practices. The logic of the prohibition: tolerated idolatry becomes contagious. The mokesh (snare) image recurs in Deut 7:16, Judg 2:3 — its anticipation here proves accurate in the subsequent history.</p>"
  },
  "24": {
    "1": "<p><b>Then he said to Moses, 'Come up to YHWH (aleh el-YHWH), you and Aaron, Nadab, and Abihu, and seventy of the elders of Israel':</b> The seventy elders (shiv'im) represent the full council of Israel (cf. Num 11:16-17; the seventy nations of Gen 10); Nadab and Abihu are Aaron's eldest sons who will later die for offering unauthorized fire (Lev 10). Their presence here at the covenant ratification makes their subsequent death more tragic — they witnessed the covenant but violated its worship standards. The number seventy = the fullness of the council.</p>",
    "2": "<p><b>Moses alone shall come near to YHWH (ve'nigash Moshe levaddo el-YHWH):</b> Nagash = to draw near (the approach verb for both priests and worshippers); levaddo = alone, by himself. The hierarchy of access is explicit: Moses alone crosses the divine threshold; the elders and Aaron worship from a distance (min-rachok = from afar). The gradation anticipates the tabernacle's concentric zones of holiness.</p>",
    "3": "<p><b>Moses came and told the people all the words of YHWH and all the rules (kol-divrei YHWH ve'et kol-hamishpatim):</b> Divrei YHWH = the words of YHWH (the Decalogue); hamishpatim = the rules/case laws (the Covenant Code of chs.21-23). <b>And all the people answered with one voice (kol-echad): 'All the words that YHWH has spoken we will do (na'aseh).'</b> The corporate consent — kol-echad (one voice) — is the ideal of covenant community. Na'aseh is the first of the famous na'aseh v'nishma of v.7.</p>",
    "4": "<p><b>And Moses wrote (vayyichtov Moshe) all the words of YHWH:</b> The first explicit statement that Moses wrote the Torah (the words of YHWH); the covenant-writing that forms the basis of the sefer ha-brit (book of the covenant). Writing creates permanence and accountability; the spoken covenant becomes a legal document. <b>He rose early in the morning (vayyashkem baboqer) and built an altar:</b> Rising early (hashkem) is the verb of diligent, devoted action throughout the Pentateuch (Abraham in Gen 22:3 — the same urgency).</p>",
    "5": "<p><b>And he sent young men (na'are) of the people of Israel, who offered burnt offerings (olot) and sacrificed peace offerings (sh'lamim) of oxen:</b> Na'ar = young man/attendant (not yet the Levitical priesthood — Aaron and his sons have not yet been ordained; these are lay offerers acting on Moses's behalf). Olah = the wholly-consumed burnt offering (from alah, to go up — the offering ascends entirely to YHWH); sh'lamim = peace/fellowship/completeness offerings (from shalom — the offering that restores wholeness and allows communion eating).</p>",
    "6": "<p><b>And Moses took half of the blood (chatzi hadam) and put it in basins, and half of the blood he threw (zaraq) against the altar:</b> The bifurcation of the covenant blood — half on the altar (YHWH's side) and half to be sprinkled on the people (v.8) — is the structural act of blood-covenant: both parties are marked with the same blood. Zaraq = to throw/sprinkle (the Levitical term for sacrificial blood-manipulation at the altar). The altar represents YHWH; the people receive the corresponding sprinkle.</p>",
    "7": "<p><b>Then he took the Book of the Covenant (sefer ha-brit) and read it in the hearing of the people:</b> Sefer ha-brit = Book of the Covenant (the first named Torah document — the written record of chs.20-23 that becomes the treaty text of the Sinai covenant). <b>And they said, 'All that YHWH has spoken we will do, and we will be obedient (na'aseh v'nishma).'</b> Na'aseh v'nishma = 'we will do and we will hear/obey' — the famous double assent. The order (doing before hearing) has fascinated rabbinic and Christian theology: the rabbis say Israel accepted the covenant before fully understanding it (trust before comprehension); Paul reads it as grace-response before law-understanding.</p>",
    "8": "<p><b>And Moses took the blood and threw it on the people (vayizroq al-ha'am) and said, 'Behold the blood of the covenant (hineh dam ha-brit) that YHWH has made with you in accordance with all these words':</b> Dam ha-brit = blood of the covenant — the defining phrase that Jesus quotes verbatim at the Last Supper (Matt 26:28: 'this is my blood of the covenant'; cf. Mark 14:24; 1 Cor 11:25). The Sinai blood-covenant is the type; Jesus's blood-covenant is the antitype. Moses's blood thrown on the people physically marks them as covenant partners; Jesus's blood covers those who receive it in faith.</p>",
    "9": "<p><b>Then Moses and Aaron, Nadab, and Abihu, and seventy of the elders of Israel went up:</b> The covenant ratification is followed immediately by covenant communion — the elders ascend to see God. The progression: proclamation (v.3) → writing (v.4) → sacrifice (v.5-6) → consent (v.7) → blood-marking (v.8) → vision (vv.9-11) is the complete covenant ratification sequence.</p>",
    "10": "<p><b>And they saw the God of Israel (vayir'u et Elohei Yisrael):</b> The elders see God — the most remarkable statement in the pericope. <b>There was under his feet as it were a pavement of sapphire stone (kivnat ha-sapir), like the very heaven for clearness:</b> Livnat = pavement/brick (from levanah = white/brick; also the word for bricks Israel made in Egypt — the redeemed slaves now see the divine pavement that transcends all human construction). Sapir = sapphire (or lapis lazuli); the heavenly blue pavement recalls Ezek 1:26 and 10:1 (the sapphire firmament under the divine throne). The clarity (kaazem hashamayim latohar = like the very sky for purity) emphasizes the absolute transparency of the divine realm.</p>",
    "11": "<p><b>And he did not lay his hand (lo shalach yado) against the chief men of the people of Israel:</b> The diplomatic understatement — YHWH had the power to destroy them for the audacity of seeing him, but restrained it (cf. Exod 33:20 — 'no man can see me and live'). The elders' survival is itself a revelation of grace. <b>They beheld God, and ate and drank:</b> The covenant meal eaten in YHWH's presence — the elders eat and drink before God in the same way that a suzerain's covenant vassals shared a table with their overlord. Covenant eating = covenant belonging.</p>",
    "12": "<p><b>YHWH said to Moses, 'Come up to me on the mountain and wait there, that I may give you the tablets of stone (luchot ha'even) with the law and the commandment (ha-Torah ve'ha-mitzvah):'</b> Luchot = tablets/boards; even = stone; Torah = instruction/teaching (the comprehensive term); mitzvah = commandment (the specific directive). The stone tablets inscribed by YHWH (31:18 — 'written with the finger of God') are the permanent documentary form of the covenant. <b>That you may teach them (l'horotam):</b> The Hiphil of yarah (to teach/instruct) — the same root as Torah; YHWH gives Moses the Torah to teach Israel.</p>",
    "13": "<p><b>So Moses rose with his assistant Joshua (Yehoshua):</b> This is Joshua's first appearance in Exodus as Moses's mesharet (minister/attendant — from sharath, to serve/minister; the same term for angels ministering before YHWH). Joshua will not go to the summit but accompanies Moses partway; his presence here anticipates his role as Moses's successor and the leader of the conquest.</p>",
    "14": "<p><b>He said to the elders, 'Wait here for us until we return to you. And behold, Aaron and Hur are with you. Whoever has a dispute (mi ba'al devarim), let him go to them.'</b> Ba'al devarim = owner of words/matters (one who has a legal case or dispute); devarim = words/matters/things. Aaron and Hur are left as judicial deputies. Hur (mentioned only here and 17:10-12 at Rephidim) is traditionally identified as the husband of Miriam or Caleb's son; he disappears from the narrative after this, which has led to speculation about his fate at the golden calf incident.</p>",
    "15": "<p><b>Then Moses went up on the mountain, and the cloud (he'anan) covered the mountain:</b> The cloud (anan) that led Israel through the wilderness now settles on Sinai as the medium of divine presence. The cloud that was a pillar of protection in transit becomes a static covering in theophany.</p>",
    "16": "<p><b>The glory of YHWH (kevod YHWH) dwelt (vayishkon) on Mount Sinai:</b> Kavod = glory/weight; shakan = to dwell/tabernacle (the root of mishkan = tabernacle, and Shekinah = divine dwelling presence). The kavod shakan formula is the technical term for the divine presence settling in a place — the same formula will be used for the tabernacle's dedication (40:34-35) and the Temple's dedication (1 Kgs 8:11). <b>And the cloud covered it six days:</b> Six days of cloud-covered silence before the seventh — the Sabbath structure of Sinai theophany mirrors the creation week.</p>",
    "17": "<p><b>Now the appearance of the glory of YHWH was like a devouring fire (ke'ur esh ocheleth) on the top of the mountain:</b> Ocheleth = consuming/devouring (from achal = to eat); the glory appears to the Israelites below as a consuming fire — the same image as Deut 4:24 ('for YHWH your God is a devouring fire') and Heb 12:29 ('our God is a consuming fire'). The fire of holiness consumes what is unholy — in the context of covenant it is simultaneously inviting and terrifying.</p>",
    "18": "<p><b>Moses entered the cloud (vayyavo Moshe betoch he'anan) and went up on the mountain:</b> The climax of the approach: Moses enters the cloud — the divine presence itself. He is not destroyed because he goes at YHWH's invitation; the covenant mediator crosses the threshold of the divine holiness under divine commission. <b>And Moses was on the mountain forty days and forty nights (arba'im yom v'arba'im lailah):</b> The first of three forty-day periods at Sinai (here; 34:28 after the golden calf; cf. Deut 9:18,25). The forty-day pattern becomes the biblical number for a complete cycle of divine preparation: Moses, Elijah at Horeb (1 Kgs 19:8), Jesus in the wilderness (Matt 4:2). Forty = the complete period of testing, transformation, and formation.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'exodus')
    merge_comm(existing, EXODUS_ORIGINAL)
    save_comm('mkt-original', 'exodus', existing)
    print('Exodus 22-24 mkt-original commentary written.')

if __name__ == '__main__':
    main()
